def main():
    def wrapper_double_underscore_for_avoiding_conflicts():

        class Vehicle:

            def __init__(self, identification):
                self.__identification = identification

            def get_identification(self):
                return self.__identification

        class Car(Vehicle):

            def __init__(self, identification, car_model):
                super().__init__(identification)
                self.car_model = car_model
                self.__identification = 'CAR' + identification

            def get_car_identification(self):
                return self.__identification
        my_car = Car('123ABC', 'Toyota Corolla')
        print(my_car.get_identification())
        print(my_car.get_car_identification())

    wrapper_double_underscore_for_avoiding_conflicts()

if __name__ == "__main__":
    main()

